import { syncUserToFirestore, fetchAllUsersFromFirestore, syncUserUpdateToFirestore, deleteUserFromFirestore, syncVisitToFirestore, syncLoginToFirestore, fetchAnalyticsFromFirestore } from "./firestoreSync.js";

// ─── Local Auth Helpers (no backend needed) ─────────────────
const AUTH_STORAGE_KEY = "navprep-users";
const SESSION_KEY = "navprep-session";
const ANALYTICS_KEY = "navprep-analytics";

const getStoredUsers = () => {
 try { return JSON.parse(localStorage.getItem(AUTH_STORAGE_KEY)) || {}; } catch { return {}; }
};

const getAnalytics = () => {
 try { return JSON.parse(localStorage.getItem(ANALYTICS_KEY)) || { totalVisits: 0, dailyHits: {}, loginHistory: [] }; } catch { return { totalVisits: 0, dailyHits: {}, loginHistory: [] }; }
};

const saveAnalytics = (data) => {
 try { localStorage.setItem(ANALYTICS_KEY, JSON.stringify(data)); } catch {}
};

// Track a page visit
const trackVisit = () => {
 const analytics = getAnalytics();
 analytics.totalVisits = (analytics.totalVisits || 0) + 1;
 const today = new Date().toISOString().split("T")[0]; // YYYY-MM-DD
 if (!analytics.dailyHits) analytics.dailyHits = {};
 analytics.dailyHits[today] = (analytics.dailyHits[today] || 0) + 1;
 saveAnalytics(analytics);
 syncVisitToFirestore(); // fire-and-forget Firestore sync
};

// Track a login event
const trackLogin = (email) => {
 const analytics = getAnalytics();
 if (!analytics.loginHistory) analytics.loginHistory = [];
 analytics.loginHistory.push({ email, timestamp: Date.now(), date: new Date().toISOString().split("T")[0] });
 // Keep last 500 entries to prevent localStorage bloat
 if (analytics.loginHistory.length > 500) analytics.loginHistory = analytics.loginHistory.slice(-500);
 saveAnalytics(analytics);
 syncLoginToFirestore(email); // fire-and-forget Firestore sync
};

const simpleHash = async (str) => {
 const encoder = new TextEncoder();
 const data = encoder.encode(str + "navprep-salt-2m");
 const hashBuffer = await crypto.subtle.digest("SHA-256", data);
 return Array.from(new Uint8Array(hashBuffer)).map(b => b.toString(16).padStart(2, "0")).join("");
};

const localAuth = {
 async signUp(email, password, displayName) {
 const users = getStoredUsers();
 const key = email.toLowerCase().trim();
 if (users[key]) throw { code: "auth/email-already-in-use", message: "An account with this email already exists." };
 if (password.length < 6) throw { code: "auth/weak-password", message: "Password must be at least 6 characters." };
 if (!email.includes("@")) throw { code: "auth/invalid-email", message: "Please enter a valid email address." };
 const hashed = await simpleHash(password);
 const user = {
 email: key,
 displayName: displayName || key.split("@")[0],
 passwordHash: hashed,
 createdAt: Date.now(),
 lastLogin: Date.now(),
 loginCount: 1,
 status: "active", // active | suspended
 subscription: "free", // free | basic | premium
 subscriptionExpiry: null, // timestamp or null
 paymentRef: null // link to payment ID later
 };
 users[key] = user;
 try { localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(users)); } catch {}
 syncUserToFirestore(user); // sync new user to Firestore
 trackLogin(key);
 const session = { email: user.email, displayName: user.displayName };
 try { localStorage.setItem(SESSION_KEY, JSON.stringify(session)); } catch {}
 return session;
 },
 async signIn(email, password) {
 const users = getStoredUsers();
 const key = email.toLowerCase().trim();
 const user = users[key];
 if (!user) throw { code: "auth/user-not-found", message: "No account found with this email." };
 const hashed = await simpleHash(password);
 if (hashed !== user.passwordHash) throw { code: "auth/wrong-password", message: "Incorrect password." };
 if (user.status === "suspended") throw { code: "auth/user-disabled", message: "Your account has been suspended. Contact admin." };
 // Update login tracking
 user.lastLogin = Date.now();
 user.loginCount = (user.loginCount || 0) + 1;
 users[key] = user;
 try { localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(users)); } catch {}
 syncUserToFirestore(user); // sync updated login info to Firestore
 trackLogin(key);
 const session = { email: user.email, displayName: user.displayName };
 try { localStorage.setItem(SESSION_KEY, JSON.stringify(session)); } catch {}
 return session;
 },
 signOut() {
 try { localStorage.removeItem(SESSION_KEY); } catch {}
 },
 getSession() {
 try { return JSON.parse(localStorage.getItem(SESSION_KEY)); } catch { return null; }
 },
 getAllUsers() {
 return getStoredUsers();
 },
 updateUser(email, updates) {
 const users = getStoredUsers();
 const key = email.toLowerCase().trim();
 if (users[key]) {
 Object.assign(users[key], updates);
 try { localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(users)); } catch {}
 syncUserUpdateToFirestore(email, updates); // sync update to Firestore
 }
 },
 deleteUser(email) {
 const users = getStoredUsers();
 delete users[email.toLowerCase().trim()];
 try { localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(users)); } catch {}
 deleteUserFromFirestore(email); // sync deletion to Firestore
 },
 getAnalytics() {
 return getAnalytics();
 }
};

