 {[["cross","Cross-Section"],["profile","Profile (Side)"],["plan","Plan (Top)"]].map(([v, l]) => (
 <button key={v} onClick={() => { setView(v); setHovered(null); }}
 style={{ border: "none", borderRadius: 8, padding: "7px 16px", fontSize: 12, fontWeight: 700, cursor: "pointer",
 background: view === v ? "#1E88E5" : "#1a2a3a", color: view === v ? "#fff" : "#90caf9",
 boxShadow: view === v ? "0 2px 8px #1E88E580" : "none", transition: "all 0.15s" }}>{l}</button>
 ))}
