 // PAGE: FORMULAS REFERENCE
 // ═══════════════════════════════════════════════
 const FormulasPage = () => {
 const [fSearch, setFSearch] = useState("");
 const allFormulas = SUBJECTS.flatMap(s =>
 s.modules.flatMap(m =>
 m.topics.flatMap(t =>
 (t.formulas || []).map(f => ({ formula: f, topicName: t.name, subjectName: s.name, subjectColor: s.color, topicId: t.id, subject: s, mod: m, topic: t }))
 )
 )
 );
 const filtered = fSearch.trim()
 ? allFormulas.filter(f => f.formula.toLowerCase().includes(fSearch.toLowerCase()) || f.topicName.toLowerCase().includes(fSearch.toLowerCase()) || f.subjectName.toLowerCase().includes(fSearch.toLowerCase()))
 : allFormulas;
 const bySubject = SUBJECTS.map(s => ({
 subject: s,
 formulas: filtered.filter(f => f.subjectName === s.name)
 })).filter(g => g.formulas.length > 0);

 return (
 <div style={css.container}>
 <BackToMainButton />
 <div style={{ marginBottom: 28 }}>
 <h1 style={css.sectionTitle}>∑ Navigational Formulas</h1>
 <p style={{ color: theme.textMuted, margin: "8px 0 20px" }}>Quick-reference — all formulas from every topic, searchable and grouped by subject. Click any formula to jump to its topic.</p>
 <input style={{ ...css.input, maxWidth: 460 }} placeholder="Search formulas or topic name..." value={fSearch} onChange={e => setFSearch(e.target.value)} />
 </div>
 {bySubject.map(({ subject: s, formulas: flist }) => (
 <div key={s.id} style={{ marginBottom: 32 }}>
 <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14, paddingBottom: 10, borderBottom: `2px solid ${s.color}30` }}>
 <span style={{ fontSize: 22 }}>{s.icon}</span>
 <h2 style={{ fontSize: 18, fontFamily: "'DM Serif Display', serif", margin: 0, color: s.color }}>{s.name}</h2>
 <span style={{ ...css.badge(s.color), marginLeft: 4 }}>{flist.length} formulas</span>
 </div>
 {flist.map((f, i) => (
 <div key={i} onClick={() => navigate("topic", f.subject, f.mod, f.topic)}
 role="button" tabIndex={0}
 onKeyDown={e=>{ if(e.key==='Enter'||e.key===' '){ e.preventDefault(); navigate("topic", f.subject, f.mod, f.topic); } }}
 style={{ display: "flex", gap: 16, alignItems: "baseline", padding: "10px 14px", borderRadius: 8, marginBottom: 6, background: theme.surfaceAlt, border: `1px solid ${theme.border}`, cursor: "pointer", transition: "border-color 0.15s" }}
 onMouseEnter={e => e.currentTarget.style.borderColor = s.color + "70"}
 onMouseLeave={e => e.currentTarget.style.borderColor = theme.border}>
 <div style={{ flex: 1, fontFamily: "'JetBrains Mono', monospace", fontSize: 13, color: theme.text, lineHeight: 1.6 }}>{f.formula}</div>
 <div style={{ fontSize: 11, color: theme.textMuted, whiteSpace: "nowrap", flexShrink: 0 }}>→ {f.topicName.slice(0, 40)}</div>
 </div>
 ))}
 </div>
 ))}
 {bySubject.length === 0 && <div style={{ textAlign: "center", padding: 60, color: theme.textMuted }}>No formulas match "{fSearch}"</div>}
 </div>
 );
 };

